import SwiftUI
import Foundation

// MARK: - ViewModel

class NetworkManager: ObservableObject {
    @Published var apiResponse: String = "No response from API yet."
    @Published var legacyResponse: String = "No response from Legacy yet."

    private let apiURL = URL(string: "https://api.example.com/data")!
    private let legacyURL = URL(string: "http://legacy.internal/status")!

    func fetchAPIData() {
        self.apiResponse = "Fetching from API..."
        URLSession.shared.dataTask(with: apiURL) { data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    self.apiResponse = "API Error: \(error.localizedDescription)"
                    print("API Request Error: \(error)")
                    return
                }

                if let httpResponse = response as? HTTPURLResponse {
                    if !(200...299).contains(httpResponse.statusCode) {
                        self.apiResponse = "API HTTP Error: \(httpResponse.statusCode)"
                        print("API HTTP Error: \(httpResponse.statusCode)")
                        return
                    }
                }

                if let data = data, let dataString = String(data: data, encoding: .utf8) {
                    self.apiResponse = "API Success: \(dataString)"
                } else {
                    self.apiResponse = "API Success: No data received or couldn't decode."
                }
            }
        }.resume()
    }

    func fetchLegacyData() {
        self.legacyResponse = "Fetching from Legacy..."
        URLSession.shared.dataTask(with: legacyURL) { data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    self.legacyResponse = "Legacy Error: \(error.localizedDescription)"
                    print("Legacy Request Error: \(error)")
                    return
                }

                if let httpResponse = response as? HTTPURLResponse {
                    if !(200...299).contains(httpResponse.statusCode) {
                        self.legacyResponse = "Legacy HTTP Error: \(httpResponse.statusCode)"
                        print("Legacy HTTP Error: \(httpResponse.statusCode)")
                        return
                    }
                }

                if let data = data, let dataString = String(data: data, encoding: .utf8) {
                    self.legacyResponse = "Legacy Success: \(dataString)"
                } else {
                    self.legacyResponse = "Legacy Success: No data received or couldn't decode."
                }
            }
        }.resume()
    }
}

// MARK: - SwiftUI Views

struct ContentView: View {
    @StateObject private var networkManager = NetworkManager()

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
